                                { substance: "Water (ice)", L_f: "334 000 J kg⁻¹ (334 kJ kg⁻¹)" },
                                { substance: "Aluminium", L_f: "397 000 J kg⁻¹" },
                                { substance: "Iron", L_f: "247 000 J kg⁻¹" },
                                { substance: "Lead", L_f: "24 700 J kg⁻¹" }
